input = sys.stdin.readline

def solve():
    n, k = map(int, input().split())
    mines = []
    for _ in range(n):
        x, y, t = map(int, input().split())
        mines.append((x, y, t))

    parent = list(range(n))
    def find(a):
        while parent[a] != a:
            parent[a] = parent[parent[a]]
            a = parent[a]
        return a
    def union(a, b):
        a, b = find(a), find(b)
        if a != b:
            parent[a] = b

    # Group by x
    by_x = defaultdict(list)
    for i, (x, y, t) in enumerate(mines):
        by_x[x].append((y, i))
    for x, lst in by_x.items():
        lst.sort()
        for j in range(1, len(lst)):
            if lst[j][0] - lst[j-1][0] <= k:
                union(lst[j][1], lst[j-1][1])

    # Group by y
    by_y = defaultdict(list)
    for i, (x, y, t) in enumerate(mines):
        by_y[y].append((x, i))
    for y, lst in by_y.items():
        lst.sort()
        for j in range(1, len(lst)):
            if lst[j][0] - lst[j-1][0] <= k:
                union(lst[j][1], lst[j-1][1])

    comp_min = {}
    for i, (x, y, t) in enumerate(mines):
        r = find(i)
        if r not in comp_min:
            comp_min[r] = t
        else:
            comp_min[r] = min(comp_min[r], t)

    timers = sorted(comp_min.values())

    # Binary search on T
    lo, hi = 0, 2 * 10**9
    while lo < hi:
        mid = (lo + hi) // 2
        # count components with min_timer > mid
        import bisect
        cnt = len(timers) - bisect.bisect_right(timers, mid)
        if cnt <= mid + 1:
            hi = mid
        else:
            lo = mid + 1
    print(lo)

